interface EQ {
  stem: string;
  options: string[];
  correctAnswer: number;
  rationale: string;
  learningObjective: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  questionType: "multiple-choice" | "image-interpretation" | "calculation" | "clinical-case";
  scenario?: string;
  exhibitData?: any;
  exam: string;
  regionScope: "US" | "CAN" | "BOTH";
}

export function getBatch41(): EQ[] {
  return [
    { stem: "The aortic valve area index (AVAi) is used to account for:", options: ["Heart rate", "Body surface area, which affects the hemodynamic significance of a given AVA; AVAi = AVA/BSA", "Rhythm", "Age"], correctAnswer: 1, rationale: "AVAi accounts for body size when assessing AS severity. Severe AS by indexed criteria: AVAi <0.6 cm²/m². A patient with large BSA may have clinically significant AS despite an AVA slightly >1.0 cm² (the unindexed threshold for severe). AVAi is particularly useful at extremes of body size.", learningObjective: "Explain the purpose of AVAi", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The energy loss index (ELI) corrects the Doppler-derived AVA for:", options: ["Heart rate", "Pressure recovery in patients with small aortas: ELI = (AVA × Aa)/(Aa - AVA), where Aa is the cross-sectional area of the sinotubular junction", "Arrhythmias", "Valve type"], correctAnswer: 1, rationale: "ELI accounts for pressure recovery, which is significant when the aorta is small (<30 mm). Doppler overestimates the net hemodynamic severity in small aortas. ELI >0.6 cm²/m² suggests the AS may be less hemodynamically severe than Doppler alone suggests.", learningObjective: "Describe the energy loss index", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 5, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the evaluation of prosthetic valve function, the Doppler velocity index (DVI) for a normally functioning aortic prosthesis is:", options: ["<0.15", "<0.25", ">0.30 (higher than native severe AS threshold because prosthetic valves inherently have some obstruction)", "DVI is not applicable to prosthetic valves"], correctAnswer: 2, rationale: "Normal prosthetic aortic DVI is typically >0.30 (compared to <0.25 for severe native AS). Each prosthesis type and size has established normal DVI ranges. A DVI <0.25 in a prosthetic valve suggests significant prosthetic valve stenosis and warrants further evaluation.", learningObjective: "Interpret DVI for prosthetic valves", blueprintCategory: "Hemodynamic Measurements", subtopic: "Prosthetic Valves", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The acceleration time (AT) of the aortic valve Doppler signal helps differentiate:", options: ["MR from MS", "AS from subaortic obstruction: AS has a longer AT (>100 ms, more symmetric envelope) while dynamic LVOT obstruction has a late-peaking dagger-shaped signal", "Systolic from diastolic function", "Left from right heart disease"], correctAnswer: 1, rationale: "Aortic AT >100 ms with a symmetric, rounded envelope suggests valvular AS. AT <80 ms with a late-peaking (concave) dagger shape suggests dynamic LVOT obstruction (HCM). An intermediate pattern may require provocative maneuvers for differentiation.", learningObjective: "Use AT to differentiate AS from dynamic obstruction", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The velocity ratio (VR) across a prosthetic mitral valve is used to detect:", options: ["AR", "Prosthetic mitral stenosis: elevated VR (E velocity / LVOT velocity) suggests obstruction across the prosthesis", "TV disease", "PDA"], correctAnswer: 1, rationale: "Prosthetic mitral valve assessment uses VR (mitral E / LVOT VTI ratio), PHT, and mean gradient. Elevated VR, prolonged PHT (>200 ms for bio, >130 ms for mechanical), and elevated mean gradient (>5-6 mmHg for bio, >6-8 for mechanical) suggest prosthetic stenosis.", learningObjective: "Assess prosthetic mitral valve with velocity ratio", blueprintCategory: "Hemodynamic Measurements", subtopic: "Prosthetic Valves", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal cardiac index is:", options: ["1.0-1.5 L/min/m²", "2.5-4.0 L/min/m²", "5.0-6.0 L/min/m²", "8.0-10.0 L/min/m²"], correctAnswer: 1, rationale: "Cardiac index = CO/BSA. Normal CI: 2.5-4.0 L/min/m². CI <2.2 L/min/m² indicates reduced cardiac output. CI <1.8 L/min/m² indicates cardiogenic shock. CI is a better hemodynamic parameter than CO because it accounts for body size.", learningObjective: "State normal cardiac index", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The stroke volume index (SVi) is used in AS classification. Low flow is defined as SVi:", options: ["<25 mL/m²", "<35 mL/m²", "<50 mL/m²", "<65 mL/m²"], correctAnswer: 1, rationale: "SVi = SV/BSA. Low flow: SVi <35 mL/m². This threshold is used to classify AS subtypes: normal flow (SVi ≥35) vs. low flow (SVi <35). Low flow can occur with reduced EF (classical low-flow) or preserved EF (paradoxical low-flow).", learningObjective: "Define low-flow threshold in AS", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with mitral E velocity of 1.5 m/s and PHT of 220 ms. The MVA by PHT is:", options: ["0.5 cm²", "1.0 cm²", "1.5 cm²", "2.0 cm²"], correctAnswer: 1, rationale: "MVA = 220/PHT = 220/220 = 1.0 cm². This indicates severe mitral stenosis (MVA <1.0 cm²). The elevated E velocity (1.5 m/s) is consistent with significant MS. Additional assessment includes mean gradient, LA pressure estimation, and PA pressure.", learningObjective: "Calculate MVA from PHT", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Coanda effect in color Doppler describes:", options: ["Normal laminar flow", "An eccentric regurgitant jet that hugs the wall of a chamber, appearing deceptively small despite being hemodynamically significant", "Aliasing", "Mirror artifact"], correctAnswer: 1, rationale: "The Coanda effect: an eccentric regurgitant jet adheres to an adjacent wall (e.g., posterior LA wall in MR from anterior leaflet prolapse). Wall-hugging jets appear smaller on color Doppler than central jets of equivalent severity, leading to underestimation of regurgitation severity.", learningObjective: "Describe the Coanda effect", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The vena contracta is measured:", options: ["At the widest part of the regurgitant jet", "At the narrowest portion of the regurgitant jet just downstream of the regurgitant orifice, in the PLAX or zoomed views", "At the proximal convergence zone", "In the receiving chamber distally"], correctAnswer: 1, rationale: "Vena contracta: the narrowest width of the regurgitant jet immediately distal to the orifice. It reflects the EROA and is relatively independent of driving pressure, flow rate, and receiving chamber constraint. Measured in the PLAX (for MR/AR) or optimized views with zoom and narrow color sector.", learningObjective: "Describe vena contracta measurement technique", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "3D vena contracta area (VCA) for severe MR is:", options: ["<0.2 cm²", "≥0.41 cm²", "≥0.20 cm² for secondary MR", "Both B and C depending on MR type"], correctAnswer: 3, rationale: "3D VCA thresholds: primary MR severe ≥0.41 cm², secondary MR severe ≥0.20 cm². 3D VCA overcomes limitations of 2D vena contracta (single plane measurement of a potentially non-circular orifice) and provides more accurate assessment of regurgitation, especially for eccentric jets.", learningObjective: "State 3D VCA thresholds for severe MR", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The color Doppler jet area to LA area ratio for assessing MR severity is:", options: ["Always accurate", "A semi-quantitative method where ratio <20% suggests mild and >40% suggests severe MR, but is influenced by technical and hemodynamic factors", "The gold standard method", "Only useful for AR"], correctAnswer: 1, rationale: "Jet area/LA area ratio: <20% = mild, 20-40% = moderate, >40% = severe. Limitations: eccentric jets underestimate (Coanda effect), gain settings, driving pressure, LA size, and loading conditions all affect jet area. This method is semi-quantitative and should be supplemented with other measurements.", learningObjective: "Interpret jet area/LA area ratio", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "When performing a PISA (proximal isovolumetric surface area) calculation for MR, the baseline is shifted to:", options: ["100 cm/s", "15-40 cm/s (toward the direction of the MR jet to optimize the hemispheric convergence zone)", "0 cm/s", "Maximum velocity"], correctAnswer: 1, rationale: "PISA technique: shift the color baseline toward the MR jet direction to 15-40 cm/s (aliasing velocity). This creates a well-defined hemispheric convergence zone. The PISA radius is measured at the first aliasing boundary. Too low an aliasing velocity creates a non-hemispheric shape.", learningObjective: "Describe PISA baseline shift technique", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An interatrial communication with a PFO can be demonstrated by:", options: ["Standard 2D imaging always", "Agitated saline injection with Valsalva release, showing bubbles crossing from RA to LA within 3-5 cardiac cycles", "Color Doppler alone always", "M-mode imaging"], correctAnswer: 1, rationale: "PFO is a flap-like opening between the septum primum and secundum. It opens when RA pressure exceeds LA pressure. Agitated saline with Valsalva (release phase raises RA pressure) is the most sensitive TTE technique. TEE with color Doppler is the gold standard. Transcranial Doppler can also detect right-to-left shunting.", learningObjective: "Demonstrate PFO with contrast study", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal LV end-diastolic volume index (EDVi) for males is:", options: ["20-40 mL/m²", "35-75 mL/m²", "80-120 mL/m²", "130-160 mL/m²"], correctAnswer: 1, rationale: "Normal LV EDVi: 35-75 mL/m² for males (biplane Simpson's). Values above this indicate LV dilation. EDVi is a volume-based measure that accounts for body size and is used to monitor ventricular remodeling in response to valvular disease and cardiomyopathies.", learningObjective: "State normal LV EDVi", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The LV end-systolic dimension (LVESD) is an important trigger for surgery in chronic severe AR. Surgery is recommended when LVESD exceeds:", options: ["35 mm", "40 mm", "50 mm (or 25 mm/m²)", "60 mm"], correctAnswer: 2, rationale: "In chronic severe AR, surgery is recommended for symptoms, LVEF ≤55%, LVESD >50 mm (or >25 mm/m²), or LVEDD >65 mm. LVESD is a reliable predictor of postoperative outcome because it reflects intrinsic myocardial contractility independent of loading conditions.", learningObjective: "State LVESD surgical trigger for AR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In chronic severe MR, surgical referral triggers include:", options: ["Mild symptoms only", "LVEF ≤60%, LVESD ≥40 mm, new atrial fibrillation, or PASP >50 mmHg at rest", "Only LVEF <30%", "Only symptoms"], correctAnswer: 1, rationale: "Surgical triggers for chronic severe primary MR: symptoms (Class I), or asymptomatic with LVEF ≤60%, LVESD ≥40 mm, new AF, PASP >50 mmHg. An LVEF of 60% in chronic MR actually represents occult dysfunction (EF should be supranormal due to favorable loading). Early repair before these thresholds is considered if expertise is available.", learningObjective: "List surgical triggers for chronic severe MR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Barlow classification of MVP refers to:", options: ["Any MVP", "Excessive myxomatous degeneration with bileaflet prolapse, redundant tissue, and annular dilation — a more severe form of degenerative MV disease", "Rheumatic MV disease", "Functional MR"], correctAnswer: 1, rationale: "Barlow disease: extensive myxomatous degeneration with thick, redundant leaflets, bileaflet involvement, chordal elongation, and annular dilation. It typically presents in younger patients. Fibroelastic deficiency (FED) is the milder form: thin leaflets with limited prolapse, typically in older patients.", learningObjective: "Define Barlow disease", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the sonographer must be able to identify the difference between:", options: ["Only stenosis and regurgitation", "Pathologic and physiologic (normal) valve regurgitation, as trace physiologic regurgitation of the tricuspid, pulmonic, and mitral valves is common and normal", "Only left and right heart disease", "Only systolic and diastolic murmurs"], correctAnswer: 1, rationale: "Physiologic (trace) regurgitation is common and normal: TR (70-80% of normal adults), PR (75-85%), MR (40-50%). These are typically brief, narrow, central jets without hemodynamic significance. Pathologic regurgitation is broader, longer, may be eccentric, and has hemodynamic consequences.", learningObjective: "Differentiate physiologic from pathologic regurgitation", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An echo shows a PFO with a right-to-left shunt at rest. This may occur with:", options: ["Normal RA pressure", "Elevated RA pressure (from pulmonary hypertension, RV infarction, or PE) or increased RA pressure from Valsalva or cough", "Only during exercise", "Only during sleep"], correctAnswer: 1, rationale: "Right-to-left PFO shunting at rest indicates RA pressure > LA pressure. Causes: pulmonary hypertension, massive PE, RV infarction, severe TR, or mechanical ventilation with high PEEP. Resting right-to-left shunt through a PFO can cause hypoxemia and paradoxical embolism.", learningObjective: "Identify conditions causing resting R-to-L PFO shunt", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch42(): EQ[] {
  return [
    { stem: "In a patient with severe TR velocity of 4.2 m/s, IVC 2.0 cm with >50% collapse, the estimated PASP is:", options: ["55.6 mmHg", "73.6 mmHg", "75.6 mmHg", "89.6 mmHg"], correctAnswer: 2, rationale: "RVSP = 4 × (4.2)² + RAP. IVC ≤2.1 cm with >50% collapse → RAP ≈ 3-5 mmHg (use 5 mmHg or 3 mmHg). 4 × 17.64 + 5 = 70.56 + 5 = 75.56 ≈ 75.6 mmHg. This indicates severe pulmonary hypertension. (Using RAP = 3: 70.56 + 3 = 73.6).", learningObjective: "Calculate PASP from clinical scenario", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The LVOT is measured in the:", options: ["A4C view at end-systole", "PLAX view during mid-systole, inner edge to inner edge, at the level of the aortic annulus", "Subcostal view in diastole", "Suprasternal view"], correctAnswer: 1, rationale: "LVOT diameter is measured in the PLAX view during mid-systole from the inner edge of the interventricular septum to the inner edge of the anterior mitral leaflet, at the level of the aortic valve annulus. Zoom imaging improves accuracy. The measurement is critical because it is squared in the area calculation.", learningObjective: "Describe LVOT measurement technique", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Strain echocardiography is angle-independent because:", options: ["It uses Doppler shift", "Speckle tracking analyzes acoustic marker displacement in all directions, unlike TDI which only measures velocities along the ultrasound beam", "It uses M-mode data", "It requires CW Doppler"], correctAnswer: 1, rationale: "STE tracks acoustic speckle patterns frame-to-frame regardless of the ultrasound beam angle. This is a major advantage over TDI-based strain, which only measures strain along the beam direction. STE can assess longitudinal, circumferential, and radial strain from standard 2D images.", learningObjective: "Explain why STE is angle-independent", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The right atrial pressure can also be estimated from the hepatic vein Doppler pattern. In elevated RAP:", options: ["S > D", "The systolic wave (S) is blunted or reversed relative to the diastolic wave (D)", "There is no change", "Only D is affected"], correctAnswer: 1, rationale: "Normal hepatic vein flow: S ≥ D. With elevated RAP, the S wave becomes blunted (S < D) or reversed because high RA pressure during systole impedes hepatic vein emptying. Systolic flow reversal is also seen with severe TR. The hepatic vein pattern complements IVC assessment for RAP estimation.", learningObjective: "Interpret hepatic vein Doppler for RAP", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The LV outflow tract obstruction in HCM can be provoked by all of the following EXCEPT:", options: ["Amyl nitrite inhalation", "Standing from squatting", "Valsalva maneuver", "Leg elevation (increases preload)"], correctAnswer: 3, rationale: "LVOT obstruction in HCM is worsened by decreased preload (Valsalva, standing, dehydration, diuretics), decreased afterload (amyl nitrite), and increased contractility (exercise, isoproterenol). Leg elevation increases preload and decreases the gradient, so it would NOT provoke obstruction.", learningObjective: "Identify maneuvers that do NOT provoke HCM obstruction", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo assessment of constrictive pericarditis should include:", options: ["Only 2D imaging", "Respirometry with Doppler to assess septal bounce, respiratory variation in mitral/tricuspid inflow, hepatic vein reversal pattern, and medial e' velocity", "Only M-mode", "Only strain imaging"], correctAnswer: 1, rationale: "Constriction assessment: septal bounce/shift on 2D/M-mode, exaggerated respiratory variation in MV inflow (>25%), TV inflow increase with inspiration, hepatic vein expiratory diastolic flow reversal, medial e' ≥9 cm/s (annulus paradoxus), and pericardial thickening (though not always present).", learningObjective: "Describe echo assessment for constriction", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Annulus paradoxus in constrictive pericarditis refers to:", options: ["Reduced annular velocity", "Preserved or elevated medial e' velocity despite restrictive filling, which is paradoxically normal in constriction but reduced in restriction", "Elevated lateral e' only", "Absent e' waves"], correctAnswer: 1, rationale: "Annulus paradoxus: medial e' is preserved/elevated (≥9 cm/s) in constriction because the medial annulus motion reflects septal bounce/exaggerated motion from ventricular interdependence, not true normal relaxation. In restriction, medial e' is reduced (<7 cm/s). This is a key differentiating feature.", learningObjective: "Define annulus paradoxus", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 5, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows interventricular dependence with a respirophasic septal shift. With inspiration, the septum shifts toward:", options: ["The RV", "The LV (as increased RV filling shifts the septum leftward, decreasing LV filling)", "Neither direction", "Posteriorly"], correctAnswer: 1, rationale: "In constriction, fixed total cardiac volume within the rigid pericardium means increased RV filling with inspiration comes at the expense of LV filling (interventricular dependence). The septum shifts toward the LV during inspiration and toward the RV during expiration (septal bounce).", learningObjective: "Describe septal shift with respiration in constriction", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Pericardial calcification on echo is:", options: ["Always visible", "Often difficult to see on echo; CT is superior for detecting pericardial calcification, which is a hallmark of chronic constrictive pericarditis", "Best seen with color Doppler", "Only visible on TEE"], correctAnswer: 1, rationale: "Pericardial calcification appears as dense, bright echoes on the pericardium but can be difficult to differentiate from other bright structures. CT is much more sensitive and specific for detecting pericardial calcification. Calcification may be focal or diffuse and is commonly seen in tuberculous or post-surgical pericarditis.", learningObjective: "Assess pericardial calcification by imaging modality", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT context, the echo assessment of a patient with atrial fibrillation should specifically evaluate:", options: ["Only heart rate", "LA size/volume, valve disease (especially mitral), LV function, LA appendage (if TEE), thromboembolic risk factors (SEC, LAA emptying velocity), and PA pressure", "Only rhythm strip", "Only LV function"], correctAnswer: 1, rationale: "Echo in AF: LA size/volume (predictor of AF persistence and recurrence), underlying valvular disease (especially MS and MR), LV function, estimated filling pressures, PA pressure, and if TEE is performed, LAA thrombus assessment and LAA emptying velocity for thromboembolic risk stratification.", learningObjective: "Describe echo assessment in atrial fibrillation", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The normal pulmonary vein flow pattern consists of:", options: ["Only systolic flow", "Systolic forward flow (S), diastolic forward flow (D), and a small atrial reversal (Ar) during atrial contraction", "Only diastolic flow", "Continuous forward flow"], correctAnswer: 1, rationale: "Normal PV flow: S wave (systolic forward flow, driven by atrial relaxation and mitral annular descent), D wave (diastolic forward flow, corresponds to early diastolic filling), and Ar wave (small reversal during atrial contraction). S ≥ D in normal adults >40 years. S < D may be normal in young adults.", learningObjective: "Describe normal pulmonary vein flow pattern", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Pulmonary vein systolic flow reversal indicates:", options: ["Normal flow", "Severe mitral regurgitation (the regurgitant volume reverses flow in the pulmonary veins during systole)", "Tricuspid regurgitation", "Aortic stenosis"], correctAnswer: 1, rationale: "PV systolic flow reversal is a specific sign of severe MR. The regurgitant jet directs blood retrograde into the pulmonary veins. It is best seen in the PV closest to the direction of the MR jet. Not all severe MR shows PV flow reversal (especially with large, compliant LA).", learningObjective: "Interpret PV systolic flow reversal", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo assessment of mitral stenosis severity should include:", options: ["Only visual assessment", "MVA (planimetry, PHT, continuity), mean gradient, PA systolic pressure, Wilkins score (if considering PBMV), and assessment of coexisting MR", "Only gradient measurement", "Only PHT method"], correctAnswer: 1, rationale: "Comprehensive MS assessment: MVA by multiple methods (planimetry = reference standard, PHT, continuity equation), mean gradient, PASP estimation, valve morphology (Wilkins score for PBMV candidacy), degree of coexisting MR (contraindication to PBMV if >mild), and exercise hemodynamics if symptoms are discordant.", learningObjective: "List components of MS severity assessment", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Exercise echo can unmask latent LVOT obstruction in HCM. A provoked gradient ≥50 mmHg indicates:", options: ["Normal response", "Hemodynamically significant obstruction that may explain exertional symptoms and may warrant treatment", "Mild disease only", "An artifact"], correctAnswer: 1, rationale: "In HCM, exercise-provoked LVOT gradient ≥50 mmHg is considered hemodynamically significant, especially if it reproduces the patient's symptoms. Approximately 1/3 of HCM patients without resting obstruction will develop obstruction with exercise. This finding may change management (add medications, consider septal reduction).", learningObjective: "Interpret exercise-provoked HCM gradient", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In Canadian echo practice, a focused cardiac ultrasound (FoCUS) study is:", options: ["A comprehensive echo", "A goal-directed bedside exam performed by non-cardiologists to answer specific clinical questions (effusion, global LV function, volume status, RV dilation) without replacing a formal comprehensive echo", "The same as a departmental echo", "Only performed by cardiologists"], correctAnswer: 1, rationale: "FoCUS is a limited, goal-directed exam using portable devices, typically performed by emergency physicians, intensivists, or anesthesiologists to rapidly assess: pericardial effusion, gross LV/RV function, IVC for volume status, and obvious valvular abnormalities. It does not replace a comprehensive echo.", learningObjective: "Define focused cardiac ultrasound", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "During dobutamine stress echo for low-flow low-gradient AS, true severe AS is confirmed when:", options: ["AVA increases to >1.5 cm²", "AVA remains <1.0 cm² despite increased flow, while the gradient increases to >40 mmHg with dobutamine stimulation", "No change occurs", "EF normalizes"], correctAnswer: 1, rationale: "True severe AS: with dobutamine, flow increases (SV ≥20% increase), gradient rises proportionally (mean >40 mmHg), but AVA stays <1.0 cm². Pseudo-severe AS: AVA increases >1.0 cm² with flow, confirming that the initial small AVA was due to low flow opening the valve incompletely, not intrinsic stenosis.", learningObjective: "Differentiate true from pseudo-severe AS", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 5, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows an ASD with a QP:Qs of 1.2 and no RV dilation. This ASD is:", options: ["Hemodynamically significant requiring closure", "Hemodynamically insignificant (Qp:Qs <1.5 without RV volume overload); serial monitoring is appropriate", "Always requiring intervention", "Impossible to assess"], correctAnswer: 1, rationale: "A Qp:Qs <1.5 without RV dilation suggests a small, hemodynamically insignificant shunt. Closure is generally not indicated. Serial follow-up monitoring for RV enlargement and shunt progression is appropriate. Closure is recommended when Qp:Qs ≥1.5 with evidence of RV volume overload.", learningObjective: "Assess ASD hemodynamic significance", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal PR end-diastolic velocity in the absence of pulmonary hypertension is:", options: ["<1.0 m/s", "<1.5 m/s", ">3.0 m/s", ">4.0 m/s"], correctAnswer: 0, rationale: "Normal PR end-diastolic velocity is <1.0 m/s (corresponding to PA diastolic pressure <4V² + RAP = <4 + 3 = <7 mmHg, which is normal). PR end-diastolic velocity >1.5-2.0 m/s suggests elevated PA diastolic pressure.", learningObjective: "State normal PR end-diastolic velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamics", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT candidates should understand that the standard LV wall thickness measurement is obtained in the:", options: ["A4C view only", "PLAX view at end-diastole, using 2D-guided M-mode or direct 2D measurement at the level of the mitral leaflet tips", "Subcostal view at end-systole", "Suprasternal view"], correctAnswer: 1, rationale: "LV wall thickness (septum and posterior wall) is measured in the PLAX view at end-diastole (onset of QRS) at the level of the mitral valve leaflet tips. 2D-guided M-mode provides high temporal resolution. Direct 2D measurement is acceptable. Leading edge to leading edge (per ASE convention).", learningObjective: "Describe LV wall thickness measurement technique", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch43(): EQ[] {
  return [
    { stem: "The PSAX view at the aortic valve level demonstrates:", options: ["LV wall segments only", "The aortic valve with three cusps (Mercedes-Benz sign in diastole), right and left atria, tricuspid and pulmonic valves, RVOT, and interatrial septum", "Only the mitral valve", "Only coronary arteries"], correctAnswer: 1, rationale: "PSAX at the AV level is one of the most information-rich echo views: AV morphology (bicuspid vs. tricuspid), both atria, IAS, tricuspid valve, RVOT and pulmonic valve, and proximal coronary arteries. This view is essential for BAV assessment, ASD evaluation, and pulmonic valve disease.", learningObjective: "Describe PSAX AV level anatomy", blueprintCategory: "Anatomy/Physiology", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The RV inflow view is obtained by:", options: ["Tilting the transducer from the PLAX view medially toward the right hip", "Tilting the transducer from the PLAX view medially (toward the right hip), showing the RA, tricuspid valve, and RV", "Rotating 90 degrees from A4C", "From the subcostal position only"], correctAnswer: 1, rationale: "The RV inflow view is obtained from the parasternal window by tilting the probe medially (toward the right hip) from the standard PLAX. It visualizes the RA, tricuspid valve (all three leaflets may be seen), and RV inflow. It is useful for TR assessment and TV morphology.", learningObjective: "Describe how to obtain the RV inflow view", blueprintCategory: "Anatomy/Physiology", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The subcostal four-chamber view is the best window for:", options: ["Aortic valve assessment", "Interatrial septum evaluation (ASD, PFO) because the ultrasound beam is perpendicular to the IAS", "Mitral valve planimetry", "Coronary artery assessment"], correctAnswer: 1, rationale: "The subcostal four-chamber view provides the ultrasound beam perpendicular to the IAS, optimizing its visualization. This is the best TTE view for detecting ASDs, measuring ASD size, and performing agitated saline contrast studies for PFO. It also visualizes the IVC and hepatic veins.", learningObjective: "Identify the best view for IAS evaluation", blueprintCategory: "Anatomy/Physiology", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Foreshortening of the LV on echo results in:", options: ["Accurate measurements", "Underestimation of LV volumes and lengths, leading to inaccurate EF calculation; the transducer is not positioned at the true apex", "Overestimation of volumes", "No effect on measurements"], correctAnswer: 1, rationale: "Foreshortening occurs when the ultrasound beam does not pass through the true LV apex, truncating the long axis. This underestimates LV length and volumes (EDV and ESV), potentially overestimating EF. Using contrast to identify the true apex or adjusting the transducer position corrects this.", learningObjective: "Describe foreshortening and its effects", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal RV/LV ratio at the basal level in the A4C view is:", options: ["<0.4", "<0.6", "0.6-1.0", ">1.5"], correctAnswer: 1, rationale: "Normal RV/LV end-diastolic diameter ratio <0.6 at the basal level (A4C view). RV/LV ratio >1.0 indicates severe RV dilation. The RV is normally about 2/3 the size of the LV in this view. Increased ratios are seen in PE, PH, RV infarction, and ARVC.", learningObjective: "State normal RV/LV ratio", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The RVOT can be measured in the:", options: ["A4C view only", "PLAX view (proximal RVOT) and PSAX at the AV level (distal RVOT)", "Subcostal view only", "Suprasternal view"], correctAnswer: 1, rationale: "RVOT dimensions: proximal RVOT measured in PLAX (normal <33 mm), distal RVOT in PSAX at AV level (normal <27 mm). RVOT dilation is one of the diagnostic criteria for ARVC (≥32 mm PLAX or ≥36 mm PSAX). RVOT diameter is also used for PW Doppler VTI measurement in Qp calculations.", learningObjective: "Describe RVOT measurement locations", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Fractional shortening (FS) is calculated as:", options: ["(EDD - ESD) / EDD × 100%", "EF × EDV", "LVOT VTI × CSA", "E/A ratio × DT"], correctAnswer: 0, rationale: "FS = (LVEDD - LVESD) / LVEDD × 100%. Normal FS: 25-45%. FS is a 1D estimate of LV systolic function from M-mode. It correlates with EF in symmetric LV contraction but is inaccurate with regional wall motion abnormalities. Biplane Simpson's EF is preferred.", learningObjective: "Calculate fractional shortening", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Bernoulli equation in its modified form accounts for:", options: ["Only peak velocity", "Proximal velocity: ΔP = 4(V2² - V1²), used when proximal velocity (V1) >1.5 m/s or when V1 exceeds V2 by less than 3:1", "Only receiver velocity", "Temperature effects"], correctAnswer: 1, rationale: "Modified Bernoulli: ΔP = 4(V2² - V1²). Used when V1 >1.5 m/s (e.g., elevated LVOT velocity in AS with significant AR, subaortic obstruction, or high cardiac output states). Ignoring V1 in these cases causes significant overestimation of the gradient.", learningObjective: "Apply the modified Bernoulli equation", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT candidates should know that the standard echo clip length for digital storage is:", options: ["1 cardiac cycle", "At least 3 cardiac cycles (or 5-10 in AF) to allow for measurement averaging and assessment of respiratory variation", "10 seconds regardless of heart rate", "30 seconds"], correctAnswer: 1, rationale: "Standard digital clips should capture at least 3 cardiac cycles (or 5-10 in AF) for measurement averaging and physiologic assessment. Clips should include clear visualization of the structures of interest and be free of motion artifact. Loop format allows for playback analysis.", learningObjective: "State standard echo clip requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An aortic intramural hematoma (IMH) appears on echo as:", options: ["Normal aortic wall", "Crescent-shaped or concentric thickening of the aortic wall (>5 mm) without an intimal flap or flow in the thickened wall", "A clearly visible intimal flap with dual lumens", "Only aortic dilation"], correctAnswer: 1, rationale: "IMH: hemorrhage within the aortic media without an intimal tear (no flap, no false lumen flow). It appears as crescentic or concentric aortic wall thickening (>5 mm, typically 7-20 mm) that is echolucent acutely and becomes echodense over time. It can progress to classic dissection.", learningObjective: "Describe IMH echo appearance", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal aortic arch dimensions in adults are:", options: ["10-15 mm", "20-35 mm", "40-50 mm", "55-65 mm"], correctAnswer: 1, rationale: "Normal aortic arch diameter is approximately 20-35 mm in adults. The arch is measured at its mid-point between the brachiocephalic and left subclavian arteries. Arch dilation >35-40 mm warrants monitoring. Aortic dimensions should be compared with BSA-indexed normograms.", learningObjective: "State normal aortic arch dimensions", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The left main coronary artery is normally:", options: ["Long and tortuous", "Short (0.5-2 cm) and divides into the LAD and circumflex arteries", "Single branch", "Located posteriorly"], correctAnswer: 1, rationale: "The left main coronary artery originates from the left coronary sinus and is typically 0.5-2 cm long before bifurcating into the LAD and left circumflex. In some patients it trifurcates with a ramus intermedius branch. Left main disease is critical and can be detected by echo in some patients.", learningObjective: "Describe left main coronary anatomy", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In Canadian practice, an echo performed for a pre-operative cardiac assessment should evaluate:", options: ["Only EF", "LV/RV function, valve disease, estimated filling pressures, PA pressure, pericardial disease, and any significant structural abnormality", "Only valve function", "Only wall motion"], correctAnswer: 1, rationale: "Pre-operative cardiac echo: LV function (EF, wall motion), RV function (TAPSE, FAC), valve disease (severity of any stenosis or regurgitation), filling pressures (E/e'), PA pressure, pericardial effusion, and structural abnormalities that may affect anesthesia or surgical planning.", learningObjective: "Describe pre-operative echo assessment", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An echo shows a dilated coronary sinus (>10 mm). Causes include all of the following EXCEPT:", options: ["Persistent left SVC", "Elevated RA pressure", "Coronary AV fistula", "Mild tricuspid regurgitation"], correctAnswer: 3, rationale: "Dilated coronary sinus (>10 mm) causes: persistent left SVC (most common), elevated RA pressure (heart failure, PH), coronary AV fistula, unroofed coronary sinus (rare), and total anomalous pulmonary venous connection to the CS. Mild TR does not cause CS dilation.", learningObjective: "List causes of dilated coronary sinus", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo-Doppler sign of a significant VSD includes:", options: ["No flow across the septum", "High-velocity systolic jet across the septum on color Doppler (restrictive VSD) or lower velocity with bidirectional flow (non-restrictive/large VSD)", "Only diastolic flow", "Color flow only in the RV"], correctAnswer: 1, rationale: "Restrictive VSD: high-velocity (4-5 m/s) left-to-right systolic jet indicates large LV-RV pressure difference (small defect). Non-restrictive VSD: lower velocity, bidirectional flow suggests equalized pressures (large defect). Color Doppler shows the jet crossing the septum.", learningObjective: "Describe VSD Doppler findings", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo finding of a rhabdomyoma in a pediatric patient should raise concern for:", options: ["Nothing significant", "Tuberous sclerosis (TSC), as cardiac rhabdomyomas are the most common cardiac tumor in children and are strongly associated with TSC", "Marfan syndrome", "Down syndrome"], correctAnswer: 1, rationale: "Rhabdomyoma: most common cardiac tumor in children. Present in 50-65% of TSC patients and are often the first manifestation of TSC. They are usually multiple, intramural, and many regress spontaneously. Rarely require surgery unless causing hemodynamic obstruction.", learningObjective: "Associate cardiac rhabdomyoma with tuberous sclerosis", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo assessment during a pericardiocentesis should monitor:", options: ["Only ECG", "Needle tip position, pericardial fluid aspiration (decreasing effusion), and cardiac chamber integrity (ensuring no chamber puncture)", "Only blood pressure", "Only heart rate"], correctAnswer: 1, rationale: "Echo-guided pericardiocentesis: identify the optimal entry site (largest pocket closest to the skin), visualize needle tip in pericardial space, monitor fluid removal, assess for residual effusion, and watch for complications (chamber perforation, pneumothorax, or laceration of coronary or internal mammary arteries).", learningObjective: "Describe echo role during pericardiocentesis", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of a 'swinging heart' within a large pericardial effusion suggests:", options: ["Normal hemodynamics", "Impending cardiac tamponade, as the heart oscillates freely within the fluid-filled pericardial sac (pendular motion)", "Constrictive pericarditis", "Myocardial ischemia"], correctAnswer: 1, rationale: "Swinging heart (pendular heart motion): the heart swings freely within a large pericardial effusion, causing alternating electrical axis on ECG (electrical alternans). While it indicates a large effusion, it is not specific for tamponade but often precedes hemodynamic compromise.", learningObjective: "Interpret swinging heart sign", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, understanding of infection control in the echo lab includes:", options: ["No specific requirements", "Transducer disinfection between patients, hand hygiene, appropriate use of gel, probe cover use for TEE, and following provincial infection control guidelines", "Only hand washing", "Only wearing gloves"], correctAnswer: 1, rationale: "Infection control in the echo lab: hand hygiene before/after patient contact, transducer cleaning/disinfection between patients (low-level for TTE, high-level for TEE), use of single-use gel packets, probe covers for invasive procedures, and adherence to provincial/institutional infection control policies.", learningObjective: "Describe infection control in the echo lab", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch44(): EQ[] {
  return [
    { stem: "The Doppler assessment of the descending aorta from the suprasternal notch view is used to detect:", options: ["Only aortic stenosis", "Holodiastolic flow reversal in severe AR and coarctation gradients", "Only PDA", "Only aortic dissection"], correctAnswer: 1, rationale: "PW Doppler in the descending aorta (suprasternal view): holodiastolic flow reversal indicates severe AR. Also used to measure coarctation peak and diastolic gradients (diastolic tail = significant coarctation). The suprasternal view also shows aortic arch anatomy.", learningObjective: "Describe suprasternal Doppler applications", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the modified Simpson's biplane method, LV volumes are calculated by:", options: ["Assuming a geometric shape", "Tracing the endocardial border in both A4C and A2C views at end-diastole and end-systole, then summing stacked discs", "Using only M-mode dimensions", "Estimating visually"], correctAnswer: 1, rationale: "Modified Simpson's: the LV endocardial border is traced in both A4C and A2C views at end-diastole and end-systole. The LV is divided into stacked discs and volumes are summed. This method makes no geometric assumptions and is the ASE-recommended technique for EF calculation.", learningObjective: "Describe modified Simpson's biplane method", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Myocardial performance index (Tei index) is prolonged in:", options: ["Normal hearts", "Both systolic and diastolic dysfunction because it combines IVCT, IVRT, and ET", "Only systolic dysfunction", "Only diastolic dysfunction"], correctAnswer: 1, rationale: "Tei index = (IVCT + IVRT) / ET. It increases with both systolic dysfunction (prolonged IVCT, shortened ET) and diastolic dysfunction (prolonged IVRT). It is a global index of cardiac performance. Normal LV Tei: <0.40 (PW Doppler), <0.48 (TDI). Normal RV Tei: <0.40 (PW), <0.55 (TDI).", learningObjective: "Interpret elevated Tei index", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal aortic valve closure-to-opening time (ejection time) is approximately:", options: ["100-150 ms", "200-350 ms", "400-500 ms", "600+ ms"], correctAnswer: 1, rationale: "Normal LV ejection time: 200-350 ms (varies with heart rate). Prolonged ET occurs with aortic stenosis (prolonged ejection through narrowed orifice). Shortened ET occurs with heart failure (reduced contractility and forward flow). ET is measured from the onset to end of the CW Doppler AV systolic signal.", learningObjective: "State normal ejection time", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A comprehensive echocardiographic assessment of a patient with suspected infective endocarditis should evaluate:", options: ["Only vegetation presence", "Vegetations (location, size, mobility), valvular destruction (perforation, flail), abscess formation, prosthetic dehiscence, new regurgitation, hemodynamic impact, and embolic complications", "Only fever etiology", "Only blood culture results"], correctAnswer: 1, rationale: "IE echo assessment: vegetation detection (TTE then TEE if negative with high clinical suspicion), vegetation characteristics (size, mobility, location), valvular destruction (regurgitation mechanism), perivalvular extension (abscess, fistula, pseudoaneurysm), hemodynamic consequences, and serial monitoring of treatment response.", learningObjective: "Describe comprehensive IE echo evaluation", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The 60/60 sign on echo suggests:", options: ["Normal hemodynamics", "Acute pulmonary embolism: RVSP <60 mmHg AND RVOT acceleration time <60 ms, distinguishing acute from chronic PH", "Severe AS", "Cardiac tamponade"], correctAnswer: 1, rationale: "60/60 sign: RVSP <60 mmHg combined with RVOT acceleration time <60 ms with mid-systolic notching. This pattern is relatively specific for acute PE because in chronic PH, the RV has adapted and can generate higher pressures (RVSP >60 mmHg). Acute PE causes acute RV pressure overload without compensatory hypertrophy.", learningObjective: "Describe the 60/60 sign for acute PE", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Echo assessment after cardiac transplantation should monitor for:", options: ["Only EF", "Allograft rejection (wall thickening, diastolic dysfunction, pericardial effusion, reduced GLS), valvular regurgitation, RV function, and cardiac allograft vasculopathy", "Only valve function", "Only pericardial effusion"], correctAnswer: 1, rationale: "Post-transplant echo: LV/RV function (baseline and serial), diastolic function (impairment may suggest rejection), wall thickness changes (rejection causes edema/thickening), pericardial effusion (common early, persistent effusion may suggest rejection), and GLS changes (early detection of rejection).", learningObjective: "Describe post-transplant echo surveillance", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal LV end-systolic volume index (ESVi) is:", options: ["5-10 mL/m²", "12-30 mL/m²", "40-60 mL/m²", "70-90 mL/m²"], correctAnswer: 1, rationale: "Normal LV ESVi: approximately 12-30 mL/m² (varies by gender and age). ESVi is used to assess LV remodeling. In chronic MR, ESVi correlates with postoperative outcomes. Values above normal indicate LV dilation/remodeling.", learningObjective: "State normal LV ESVi", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "For CSCT practice, the echo assessment of a patient with dyspnea should evaluate:", options: ["Only LV EF", "LV systolic and diastolic function, valve disease, filling pressures (E/e'), PA pressure, RV function, pericardial disease, and IVC for volume status", "Only chest X-ray findings", "Only respiratory function"], correctAnswer: 1, rationale: "Dyspnea echo assessment: LV function (systolic and diastolic), valve disease, filling pressures (E/e', LA volume), PA pressure, RV function, pericardial effusion, IVC for volume status, and wall motion abnormalities. Echo is the first-line cardiac imaging for dyspnea evaluation.", learningObjective: "Describe echo assessment for dyspnea", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The normal aortic annulus diameter is:", options: ["10-15 mm", "18-25 mm", "30-38 mm", "40-50 mm"], correctAnswer: 1, rationale: "Normal aortic annulus diameter: approximately 18-25 mm (body-size dependent). It is measured in the PLAX view during mid-systole, inner edge to inner edge. The annulus diameter is used for LVOT area calculation (assumed equal to LVOT diameter) and for TAVR sizing.", learningObjective: "State normal aortic annulus diameter", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The mitral annular dimensions are important in functional MR because:", options: ["They determine valve area", "Annular dilation >35-38 mm (or >23 mm/m²) directly causes leaflet malcoaptation and is an independent mechanism of functional MR and a criterion for annuloplasty ring sizing", "They affect only diastolic function", "They have no clinical significance"], correctAnswer: 1, rationale: "Mitral annular dilation: AP diameter >35 mm or indexed >23 mm/m² (measured in PLAX or A4C at end-diastole). Annular dilation prevents leaflet coaptation, causing functional MR. Annuloplasty addresses this by reducing annular size. The saddle shape is lost with annular dilation.", learningObjective: "Explain the role of annular dilation in functional MR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT context, the difference between pulsed-wave and continuous-wave Doppler in clinical practice is:", options: ["They provide identical information", "PW provides velocity at a specific depth (range resolution) but aliases at high velocities; CW measures high velocities without aliasing but lacks range resolution", "PW is always preferred", "CW is obsolete"], correctAnswer: 1, rationale: "Clinical application: PW is used for localized velocity measurement (LVOT, mitral annulus TDI, PV flow). CW is used for high-velocity jets (AS, MR, TR, MS) where peak velocity exceeds the Nyquist limit. Understanding when to use each is a core competency.", learningObjective: "Apply PW vs. CW Doppler clinically", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The right coronary artery originates from the:", options: ["Left coronary sinus", "Right coronary sinus of Valsalva", "Non-coronary sinus", "Aortic arch"], correctAnswer: 1, rationale: "The RCA originates from the right (anterior) coronary sinus of Valsalva. It courses along the right AV groove, giving rise to the acute marginal branch and in 85% of patients, the PDA. The proximal RCA can sometimes be visualized on TTE in the PSAX view at the AV level.", learningObjective: "Identify RCA origin", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The clinical significance of an anomalous left coronary artery from the pulmonary artery (ALCAPA) is:", options: ["Benign finding", "Causes myocardial ischemia/infarction as pulmonary artery pressure drops after birth, resulting in left coronary steal; presents in infancy with LV dysfunction", "Only seen in adults", "Only causes arrhythmias"], correctAnswer: 1, rationale: "ALCAPA (Bland-White-Garland syndrome): the left coronary arises from the PA. After birth, falling PA pressure reduces left coronary perfusion, causing ischemia and coronary steal (retrograde flow from right coronary collaterals into the low-pressure PA). Presents with LV dysfunction, MR, and possible MI in infancy.", learningObjective: "Describe ALCAPA clinical significance", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A type A aortic dissection involves:", options: ["Only the descending aorta", "The ascending aorta (regardless of origin), which requires emergent surgical repair", "Only the aortic arch", "Only the abdominal aorta"], correctAnswer: 1, rationale: "Stanford Type A: any dissection involving the ascending aorta, regardless of the site of origin or distal extent. Type A is a surgical emergency (mortality ~1-2% per hour without treatment). TEE is the imaging modality of choice in the OR. It can assess the extent, AV competence, and coronary involvement.", learningObjective: "Classify Type A aortic dissection", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a mobile, pedunculated mass in the RA attached to the IAS. The most likely diagnosis is:", options: ["Thrombus", "Myxoma (RA myxomas are less common than LA but also arise from the IAS, typically at the fossa ovalis)", "Vegetation", "Lipoma"], correctAnswer: 1, rationale: "RA myxomas represent ~15-20% of cardiac myxomas (vs. ~75% LA). They arise from the IAS (fossa ovalis region), are pedunculated, mobile, and may obstruct the tricuspid valve. RA thrombus is usually associated with central lines, pacemaker leads, or hypercoagulable states.", learningObjective: "Diagnose RA myxoma", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of severe pulmonary regurgitation includes:", options: ["Only color Doppler jet", "Dense CW signal with rapid equalization of PA and RV pressures (short PHT), wide vena contracta, and often normal or low PA pressures if chronic", "Elevated PR jet velocity always", "Only mild RV dilation"], correctAnswer: 1, rationale: "Severe PR: dense CW Doppler signal with rapid pressure equalization (short PHT/steep deceleration slope), wide color jet filling the RVOT (>65% of RVOT width), laminar holodiastolic flow reversal in PA branches, RV dilation, and possibly flattened interventricular septum.", learningObjective: "Describe severe PR echo findings", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT-style question: the echo lab receives a referral for 'echo for murmur.' The sonographer should:", options: ["Only check for valve disease", "Perform a comprehensive TTE with particular attention to all valves (morphology, stenosis, regurgitation), hemodynamic assessment, and any associated findings", "Only assess the aortic valve", "Only measure EF"], correctAnswer: 1, rationale: "A referral for 'murmur evaluation' requires a comprehensive TTE because the murmur source is unknown. The sonographer should systematically evaluate all valves for stenosis and regurgitation, assess chamber sizes, LV/RV function, and any associated findings (dilation, hypertrophy, PAH).", learningObjective: "Describe sonographer approach to murmur evaluation", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch45(): EQ[] {
  return [
    { stem: "The speed of sound in soft tissue used in diagnostic ultrasound is:", options: ["330 m/s", "1000 m/s", "1540 m/s", "3000 m/s"], correctAnswer: 2, rationale: "The assumed speed of sound in soft tissue is 1540 m/s. This calibration is used by the machine to calculate distances (depth = time × speed / 2). If sound travels through tissues with significantly different speeds (fat: ~1450 m/s, bone: ~4000 m/s), spatial registration errors occur.", learningObjective: "State the speed of sound in soft tissue", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The duty factor of a diagnostic ultrasound transducer is:", options: ["100% (always transmitting)", "Usually <1% (the transducer spends most of its time receiving, not transmitting)", "50%", "75%"], correctAnswer: 1, rationale: "Duty factor = (pulse duration / pulse repetition period) × 100%. In B-mode imaging, the transducer transmits for approximately 0.1-1% of the time and receives for ~99%. Higher duty factors (closer to 50%) occur with CW Doppler, which transmits continuously.", learningObjective: "State the typical duty factor", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The pulse repetition frequency (PRF) is determined by:", options: ["Transducer frequency only", "The depth of imaging (deeper imaging requires lower PRF to allow echoes to return before the next pulse)", "Crystal thickness", "Gain settings"], correctAnswer: 1, rationale: "PRF is determined by imaging depth: PRF = c / (2 × depth). Deeper imaging requires more time for echo return, reducing PRF. PRF affects: Doppler aliasing (Nyquist limit = PRF/2), frame rate, and temporal resolution. Typical PRF: 1-10 kHz for B-mode.", learningObjective: "Describe PRF determinants", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The spatial peak temporal average (SPTA) intensity is the most relevant bioeffects parameter because:", options: ["It measures peak pressure only", "It represents the maximum intensity at any point averaged over time, reflecting the total energy delivered to the tissue at the point of highest exposure", "It is always zero", "It only measures mechanical effects"], correctAnswer: 1, rationale: "SPTA = intensity at the spatial peak location averaged over time. It is the most clinically relevant parameter for thermal bioeffects (tissue heating). FDA limits SPTA to 720 mW/cm² for diagnostic cardiac imaging. Higher SPTA occurs with CW Doppler and color Doppler.", learningObjective: "Define SPTA intensity", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the sonographer must understand that pulsed-wave Doppler sample volume is placed:", options: ["Anywhere", "At specific anatomic locations depending on what is being measured (mitral leaflet tips for E/A, annulus for TDI, LVOT for VTI, PV orifice for PV flow)", "Only at one standard location", "Randomly within the heart"], correctAnswer: 1, rationale: "PW Doppler sample volume placement is standardized: mitral leaflet tips for E/A ratio, medial and lateral mitral annulus for TDI e', LVOT just below the AV for VTI, pulmonary vein orifice for PV flow, and hepatic vein for HV flow. Correct placement is essential for accurate measurements.", learningObjective: "Describe PW sample volume placement locations", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The left circumflex artery supplies which LV wall segments?", options: ["Anterior wall and anterior septum", "Inferolateral and anterolateral walls (in left-dominant circulation, also the inferior wall)", "Only the RV free wall", "Only the apex"], correctAnswer: 1, rationale: "The LCx supplies the inferolateral (posterior) and anterolateral walls via obtuse marginal branches. In left-dominant circulation (~8-15%), the LCx also gives rise to the PDA and supplies the inferior wall and posterior septum. Wall motion abnormalities in these regions suggest LCx disease.", learningObjective: "Map LCx coronary territory", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo appearance of a cardiac fibroma is:", options: ["Cystic structure", "Well-circumscribed, homogeneous, echogenic intramural mass, typically in the LV free wall or septum, usually solitary", "Multiple mobile masses", "Pedunculated mass on a valve"], correctAnswer: 1, rationale: "Cardiac fibroma: second most common pediatric cardiac tumor. Solitary, intramural, well-circumscribed, homogeneous, and echogenic. Most commonly in the LV free wall or septum. Unlike rhabdomyomas, fibromas do not regress and may require surgical resection if causing obstruction or arrhythmias.", learningObjective: "Describe cardiac fibroma echo appearance", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the Doppler equation, the cosine of the angle between the ultrasound beam and blood flow direction is important because:", options: ["It has no effect", "At angles >20 degrees, the cosine function causes progressively greater underestimation of true velocity (at 60 degrees, velocity is underestimated by 50%)", "It only affects CW Doppler", "It overestimates velocity"], correctAnswer: 1, rationale: "V = Δf × c / (2 × f₀ × cos θ). At 0°: cos = 1 (accurate). At 20°: cos = 0.94 (6% error). At 30°: cos = 0.87 (13% error). At 60°: cos = 0.50 (50% underestimation). At 90°: cos = 0 (no signal). Angles ≤20° are considered acceptable for clinical accuracy.", learningObjective: "Explain the cosine angle effect on Doppler velocity", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "HPRF (high pulse repetition frequency) Doppler is a compromise between PW and CW that:", options: ["Is identical to standard PW", "Uses multiple sample gates along the beam to extend the Nyquist limit while maintaining some range resolution", "Has no aliasing limit", "Is only used in pediatrics"], correctAnswer: 1, rationale: "HPRF Doppler sends multiple pulses before receiving all echoes, creating multiple sample gates. This effectively increases the PRF (and Nyquist limit) while maintaining some range resolution. The tradeoff is range ambiguity: the velocity measurement could come from any of the sample gate locations.", learningObjective: "Describe HPRF Doppler", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Phased array transducers used in cardiac imaging differ from linear array transducers in that they:", options: ["Have a larger footprint", "Have a small footprint with electronic beam steering that creates a sector-shaped image, ideal for intercostal acoustic windows", "Cannot perform Doppler", "Only produce M-mode images"], correctAnswer: 1, rationale: "Phased array transducers have a small footprint (~2 cm) that fits between ribs, with electronic steering that creates a wide sector (typically 90°). They are the standard for cardiac imaging. Linear arrays have large footprints for vascular/superficial imaging with rectangular fields of view.", learningObjective: "Describe phased array transducer characteristics", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a patient with cardiac involvement of sarcoidosis. The echo findings may include:", options: ["Only normal echo", "Basal septal thinning, patchy wall motion abnormalities (non-coronary distribution), aneurysms, and reduced EF", "Only concentric hypertrophy", "Only pericardial effusion"], correctAnswer: 1, rationale: "Cardiac sarcoidosis: patchy granulomatous infiltration causing regional wall motion abnormalities in non-coronary distribution, basal septal thinning (characteristic), ventricular aneurysms, conduction disease, and reduced EF. Cardiac MRI with late gadolinium enhancement is more sensitive than echo.", learningObjective: "Describe cardiac sarcoidosis echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In Canadian echo labs, the recommended scanning time for a comprehensive adult TTE is approximately:", options: ["5-10 minutes", "15-20 minutes", "30-45 minutes (including image acquisition, measurements, and preliminary review)", "60-90 minutes"], correctAnswer: 2, rationale: "A comprehensive adult TTE typically takes 30-45 minutes for complete image acquisition and measurements. Complex cases (multiple pathologies, difficult windows, post-surgical) may take longer. Labs should ensure adequate scheduling to maintain quality without rushing through the protocol.", learningObjective: "State approximate TTE scanning time", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The normal ascending aorta diameter in adults is:", options: ["15-20 mm", "21-37 mm", "40-50 mm", "55+ mm"], correctAnswer: 1, rationale: "Normal ascending aorta diameter: 21-37 mm (varies by age, sex, BSA). Dilation >37-40 mm warrants monitoring. Aneurysm is generally defined as ≥1.5× expected normal diameter. BSA-indexed dimensions should be used for more accurate assessment.", learningObjective: "State normal ascending aorta diameter", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows LV apical hypertrophy with a 'spade-shaped' (ace-of-spades) LV cavity. This pattern is characteristic of:", options: ["DCM", "Apical HCM (Yamaguchi variant)", "Cardiac amyloidosis", "LV non-compaction"], correctAnswer: 1, rationale: "Apical HCM (Yamaguchi variant): predominant hypertrophy at the LV apex, creating an ace-of-spades or spade-shaped cavity. It may be missed on standard views if the apex is foreshortened. Giant negative T-waves on ECG are characteristic. Contrast echo improves detection.", learningObjective: "Identify apical HCM pattern", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "For CSCT candidates, the importance of scanning technique includes:", options: ["Only image orientation", "Proper patient positioning, transducer selection, optimal gain/depth/focus settings, systematic approach to all views, and documentation per lab protocol", "Only Doppler settings", "Only recording clips"], correctAnswer: 1, rationale: "Proper scanning technique encompasses: left lateral decubitus positioning, appropriate transducer selection (2-4 MHz phased array for adults), optimal gain/depth/focus settings, systematic acquisition of all standard views, complete Doppler assessment, and documentation according to lab protocol.", learningObjective: "Describe comprehensive scanning technique components", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}
